import Link from "next/link";
import { HorizontalBarChart } from "@/components/donor/transparency-charts";
import { PageContainer } from "@/components/layout/page-container";
import { ApplicationStatusBadge } from "@/components/ui/application-status-badge";
import { Button } from "@/components/ui/button";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table";
import { ClipboardCheck, Clock3, FileCheck2, Users } from "lucide-react";
import { createSupabaseServerClient } from "@/lib/supabase/server";
import { getAdminApplications } from "@/lib/supabase/actions";
import { resolveUserRoleForSession } from "@/lib/auth/roles";
import { redirect } from "next/navigation";

type AdminApplication = Awaited<
  ReturnType<typeof getAdminApplications>
>[number];

function isPendingReviewStatus(status: string) {
  return status === "submitted" || status === "under_review";
}
function isInterviewStageStatus(status: string) {
  return status === "interview_stage";
}
function isDecisionReadyStatus(status: string) {
  return status === "shortlisted";
}
function getScoreLabel(score: unknown) {
  return typeof score === "number" && Number.isFinite(score)
    ? `${score}/100`
    : "Awaiting";
}
function getCohortLabel(cohortYear: unknown) {
  return typeof cohortYear === "number" || typeof cohortYear === "string"
    ? `Cohort ${cohortYear}`
    : "Unassigned";
}

export default async function ApplicationsManagementPage() {
  const supabase = await createSupabaseServerClient();
  const {
    data: { user },
  } = await supabase.auth.getUser();
  if (!user) redirect("/login");

  const role = await resolveUserRoleForSession(supabase, user);
  if (role !== "admin" && role !== "reviewer") redirect("/admin");

  const applications = await getAdminApplications();
  const vis = applications.filter(
    (a: AdminApplication) => a.status !== "draft"
  );

  const totalApplicants = vis.length;
  const pendingReview = vis.filter((a: AdminApplication) =>
    isPendingReviewStatus(a.status)
  ).length;
  const interviewStage = vis.filter((a: AdminApplication) =>
    isInterviewStageStatus(a.status)
  ).length;
  const decisionReady = vis.filter((a: AdminApplication) =>
    isDecisionReadyStatus(a.status)
  ).length;

  const metrics = [
    {
      title: "Total Applicants",
      value: totalApplicants.toLocaleString(),
      description: "Across open application windows",
    },
    {
      title: "Pending Review",
      value: pendingReview.toString(),
      description: "Need reviewer assignment",
    },
    {
      title: "Interviews Active",
      value: interviewStage.toString(),
      description: "Currently in interview cycle",
    },
    {
      title: "Decision Ready",
      value: decisionReady.toString(),
      description: "Awaiting final approval",
    },
  ];

  const pipelineData = [
    { label: "Intake", value: totalApplicants > 0 ? 100 : 0, color: "#475569" },
    {
      label: "Screening",
      value: Math.round(
        (vis.filter((a: AdminApplication) => !["submitted"].includes(a.status))
          .length /
          (totalApplicants || 1)) *
          100
      ),
      color: "#0284c7",
    },
    {
      label: "Interview",
      value: Math.round(
        (vis.filter((a: AdminApplication) =>
          ["interview_stage", "shortlisted", "accepted"].includes(a.status)
        ).length /
          (totalApplicants || 1)) *
          100
      ),
      color: "#d97706",
    },
    {
      label: "Offer",
      value: Math.round(
        (vis.filter((a: AdminApplication) => a.status === "accepted").length /
          (totalApplicants || 1)) *
          100
      ),
      color: "#0f766e",
    },
  ];

  return (
    <PageContainer
      title="Applications Management"
      section="Admin"
      description="Monitor intake volume, reviewer queues, scoring progress, interviews, and final decisions."
      action={
        <Button asChild size="sm" className="rounded-md">
          <Link href="/admin/applications/review">Open Review</Link>
        </Button>
      }
    >
      <div className="space-y-5">
        {/* Metrics */}
        <div className="grid md:grid-cols-2 xl:grid-cols-4 border border-border/50 rounded-xl overflow-hidden divide-x divide-border/50">
          {metrics.map((m, i) => (
            <div key={i} className="border-t-2 border-foreground px-5 py-5">
              <p className="text-[10px] font-bold uppercase tracking-widest text-muted-foreground mb-1.5">
                {m.title}
              </p>
              <p className="text-3xl font-semibold tracking-tight leading-none mb-1">
                {m.value}
              </p>
              <p className="text-[11px] text-muted-foreground">
                {m.description}
              </p>
            </div>
          ))}
        </div>

        <div className="grid gap-5 xl:grid-cols-[1.05fr_0.95fr]">
          {/* Pipeline */}
          <div className="border border-border/50 rounded-xl overflow-hidden">
            <div className="px-5 py-3.5 border-b border-border/50 bg-muted/20">
              <p className="text-xs font-semibold">Application Pipeline</p>
              <p className="text-[11px] text-muted-foreground mt-0.5">
                Conversion from intake through final decision issuance.
              </p>
            </div>
            <div className="p-5">
              <HorizontalBarChart items={pipelineData} valueSuffix="%" />
            </div>
          </div>

          {/* Reviewer Load */}
          <div className="border border-border/50 rounded-xl overflow-hidden">
            <div className="px-5 py-3.5 border-b border-border/50 bg-muted/20">
              <p className="text-xs font-semibold">Reviewer Load</p>
              <p className="text-[11px] text-muted-foreground mt-0.5">
                Current reviewer queues, specialisations, and turnaround.
              </p>
            </div>
            <div className="p-5">
              <div className="border border-border/50 rounded-lg bg-muted/20 p-4">
                <div className="flex items-center justify-between gap-4 mb-2">
                  <p className="text-xs font-semibold">System Auto-Review</p>
                  <span className="text-xs font-semibold">
                    {pendingReview} in queue
                  </span>
                </div>
                <p className="text-[11px] text-muted-foreground mb-3">
                  Initial screening and scoring
                </p>
                <p className="text-[10px] font-bold uppercase tracking-widest text-muted-foreground">
                  SLA: 24 Hours
                </p>
              </div>
            </div>
          </div>
        </div>

        {/* Applications Queue */}
        <div className="border border-border/50 rounded-xl overflow-hidden">
          <div className="flex items-center justify-between px-5 py-3.5 border-b border-border/50 bg-muted/20">
            <div>
              <p className="text-xs font-semibold">Applications Queue</p>
              <p className="text-[11px] text-muted-foreground mt-0.5">
                Live queue for reviewer assignment, scoring, and interview
                coordination.
              </p>
            </div>
            <Button
              asChild
              variant="outline"
              size="sm"
              className="rounded-md text-xs"
            >
              <Link href="/admin/applications/review">Review featured</Link>
            </Button>
          </div>
          <Table>
            <TableHeader>
              <TableRow>
                <TableHead>Applicant</TableHead>
                <TableHead>Email</TableHead>
                <TableHead>Cohort</TableHead>
                <TableHead>Status</TableHead>
                <TableHead>Score</TableHead>
              </TableRow>
            </TableHeader>
            <TableBody>
              {vis.map((a: AdminApplication) => (
                <TableRow key={a.id}>
                  <TableCell>
                    <p className="font-medium text-sm">
                      {a.profiles?.first_name} {a.profiles?.last_name}
                    </p>
                    <p className="text-[11px] text-muted-foreground">
                      {a.id.slice(0, 8)}
                    </p>
                  </TableCell>
                  <TableCell className="text-sm">
                    {a.profiles?.email || "—"}
                  </TableCell>
                  <TableCell>
                    <p className="text-sm">{getCohortLabel(a.cohort_year)}</p>
                    <p className="text-[11px] text-muted-foreground">
                      Step {a.current_step ?? "N/A"}
                    </p>
                  </TableCell>
                  <TableCell>
                    <ApplicationStatusBadge status={a.status} />
                  </TableCell>
                  <TableCell className="text-sm">
                    {getScoreLabel(a.score)}
                  </TableCell>
                </TableRow>
              ))}
              {vis.length === 0 && (
                <TableRow>
                  <TableCell
                    colSpan={5}
                    className="text-center py-8 text-xs text-muted-foreground"
                  >
                    No applications submitted yet.
                  </TableCell>
                </TableRow>
              )}
            </TableBody>
          </Table>
        </div>
      </div>
    </PageContainer>
  );
}

import Link from "next/link";
import { PageContainer } from "@/components/layout/page-container";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { getAdminApplications, getAdminApplicationById, getAvailableCohorts } from "@/lib/supabase/actions";
import { ReviewWorkspace } from "@/components/admin/review-workspace";
import { redirect } from "next/navigation";
import { createSupabaseServerClient } from "@/lib/supabase/server";
import { resolveUserRoleForSession } from "@/lib/auth/roles";

export default async function ApplicationReviewPage({
    searchParams,
}: {
    searchParams: Promise<{ id?: string }>;
}) {
    const { id } = await searchParams;
    const supabase = await createSupabaseServerClient();
    const { data: { user } } = await supabase.auth.getUser();

    if (!user) {
        redirect("/login");
    }

    const role = await resolveUserRoleForSession(supabase, user);
    if (role !== "admin" && role !== "reviewer") {
        redirect("/admin");
    }

    let application = null;
    const cohorts = await getAvailableCohorts();

    if (id) {
        application = await getAdminApplicationById(id);
    } else {
        // Fetch the first available application as a fallback for "featured"
        const allApplications = await getAdminApplications();
        const prioritizedApplication = allApplications.find((candidate) => candidate.status !== "draft");
        if (prioritizedApplication) {
            application = prioritizedApplication;
        } else if (allApplications.length > 0) {
            application = allApplications[0];
        }
    }

    if (!application) {
        return (
          <PageContainer
            title="Application Review"
            description="No application selected for review."
            action={
              <Button asChild variant="outline">
                <Link href="/admin/applications">Back to Applications</Link>
              </Button>
            }
          >
            <div className="border border-border/50 rounded-xl overflow-hidden">
              <div className="px-5 py-3.5 border-b border-border/50 bg-muted/20">
                <p className="text-xs font-semibold">No Application Found</p>
                <p className="text-[11px] text-muted-foreground mt-0.5">
                  Please select an application from the queue to start a review.
                </p>
              </div>
              <div className="p-5">
                <Button asChild size="sm" className="rounded-md">
                  <Link href="/admin/applications">
                    Go to Application Queue
                  </Link>
                </Button>
              </div>
            </div>
          </PageContainer>
        );
    }

    return (
        <PageContainer
            title="Application Review"
            description="Assign reviewers, score the application, and issue a decision."
            action={
                <Button asChild variant="outline">
                    <Link href="/admin/applications">Back to Applications</Link>
                </Button>
            }
        >
            <ReviewWorkspace application={application} cohorts={cohorts} />
        </PageContainer>
    );
}

import Link from "next/link";
import { MetricCard } from "@/components/cards/metric-card";
import {
    DonutBreakdownChart,
    HorizontalBarChart,
} from "@/components/donor/transparency-charts";
import { PageContainer } from "@/components/layout/page-container";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import {
    Table,
    TableBody,
    TableCell,
    TableHead,
    TableHeader,
    TableRow,
} from "@/components/ui/table";
import { AlertCircle, Banknote, Briefcase, WalletCards } from "lucide-react";
import { createSupabaseServerClient } from "@/lib/supabase/server";
import { getAdminFundingLedger, getAdminPrograms, getAdminScholars, getAdminSponsors } from "@/lib/supabase/actions";
import { redirect } from "next/navigation";
import { AllocateFundingDialog } from "@/components/admin/allocate-funding-dialog";

function getFundingStatusClass(status: string) {
    if (status === "completed" || status === "Disbursed") return "bg-emerald-100 text-emerald-800";
    if (status === "pending" || status === "Committed") return "bg-blue-100 text-blue-800";
    return "bg-red-100 text-red-800";
}

export default async function FundingManagementPage() {
    const supabase = await createSupabaseServerClient();
    const { data: { user } } = await supabase.auth.getUser();

    if (!user) {
        redirect("/login");
    }

    const ledger = await getAdminFundingLedger();
    const sponsors = await getAdminSponsors();
    const scholars = await getAdminScholars();
    const programs = await getAdminPrograms();

    const committed = ledger.filter((l: any) => l.status === "pending" || l.status === "Committed").reduce((acc: number, l: any) => acc + Number(l.amount), 0);
    const disbursed = ledger.filter((l: any) => l.status === "completed" || l.status === "Disbursed").reduce((acc: number, l: any) => acc + Number(l.amount), 0);
    const flagged = ledger.filter((l: any) => l.status === "flagged" || l.status === "Flagged").reduce((acc: number, l: any) => acc + Number(l.amount), 0);
    const reserved = 640000000; // Mock or future: fetch from treasury table

    const fundingMetrics = [
        { title: "Committed", value: `N${(committed / 1000000000).toFixed(2)}B`, description: "Approved sponsor funding", icon: WalletCards },
        { title: "Disbursed", value: `N${(disbursed / 1000000000).toFixed(2)}B`, description: "Released across active lines", icon: Banknote },
        { title: "Reserved", value: `N${(reserved / 1000000).toFixed(0)}M`, description: "Held for future releases", icon: Briefcase },
        { title: "Flagged", value: `N${(flagged / 1000000).toFixed(0)}M`, description: "Needs compliance follow-up", icon: AlertCircle },
    ];

    const programDistribution = ledger.reduce((acc: any, curr: any) => {
        const progName = curr.programs?.name || "Other";
        acc[progName] = (acc[progName] || 0) + Number(curr.amount);
        return acc;
    }, {});

    const distributionItems = Object.entries(programDistribution).map(([label, value]: [string, any], index) => ({
        label,
        value: Number(value),
        color: ["#0f766e", "#0284c7", "#d97706", "#dc2626", "#475569"][index % 5],
        description: `Total funding for ${label}`,
        meta: `N${(Number(value) / 1000000).toFixed(0)}M`
    }));

    return (
        <PageContainer
            title="Funding Management"
            description="Manage allocations, disbursements, sponsor coverage, and funding watchlists across the platform."
            action={
                <div className="flex items-center gap-3">
                    <Button asChild variant="outline">
                        <Link href="/admin/sponsors">Open Sponsors</Link>
                    </Button>
                    <AllocateFundingDialog sponsors={sponsors} scholars={scholars} programs={programs} />
                </div>
            }
        >
            <div className="space-y-6">
                <div className="grid gap-4 md:grid-cols-2 xl:grid-cols-4">
                    {fundingMetrics.map((metric) => (
                        <MetricCard
                            key={metric.title}
                            title={metric.title}
                            value={metric.value}
                            description={metric.description}
                            icon={metric.icon}
                            className="border-border/60"
                        />
                    ))}
                </div>

                <div className="grid gap-6 xl:grid-cols-[1fr_1fr]">
                    <Card className="border-border/60">
                        <CardHeader>
                            <CardTitle>Programme Funding Mix</CardTitle>
                            <CardDescription>How committed funding is split across active programme lines.</CardDescription>
                        </CardHeader>
                        <CardContent>
                            <DonutBreakdownChart
                                items={distributionItems}
                                totalLabel="Committed"
                                totalValue={`N${(committed / 1000000000).toFixed(2)}B`}
                            />
                        </CardContent>
                    </Card>

                    <Card className="border-border/60">
                        <CardHeader>
                            <CardTitle>Sponsor Contribution Status</CardTitle>
                            <CardDescription>Capital concentration by major donor categories.</CardDescription>
                        </CardHeader>
                        <CardContent>
                            <HorizontalBarChart
                                items={distributionItems.slice(0, 4)}
                                valueSuffix="M"
                            />
                        </CardContent>
                    </Card>
                </div>

                <Card className="border-border/60">
                    <CardHeader>
                        <CardTitle>Funding Ledger</CardTitle>
                        <CardDescription>Current commitments, disbursements, and flagged funding lines by programme and sponsor.</CardDescription>
                    </CardHeader>
                    <CardContent>
                        <Table>
                            <TableHeader>
                                <TableRow>
                                    <TableHead>Programme</TableHead>
                                    <TableHead>Sponsor</TableHead>
                                    <TableHead>Amount</TableHead>
                                    <TableHead>Date</TableHead>
                                    <TableHead>Status</TableHead>
                                </TableRow>
                            </TableHeader>
                            <TableBody>
                                {ledger.map((entry: any) => (
                                    <TableRow key={entry.id}>
                                        <TableCell>{entry.programs?.name || "—"}</TableCell>
                                        <TableCell>
                                            {entry.profiles?.first_name} {entry.profiles?.last_name}
                                        </TableCell>
                                        <TableCell>N{Number(entry.amount).toLocaleString()}</TableCell>
                                        <TableCell>{new Date(entry.date).toLocaleDateString()}</TableCell>
                                        <TableCell>
                                            <span className={`inline-flex rounded-full px-2.5 py-0.5 text-xs font-semibold ${getFundingStatusClass(entry.status)}`}>
                                                {entry.status}
                                            </span>
                                        </TableCell>
                                    </TableRow>
                                ))}
                                {ledger.length === 0 && (
                                    <TableRow>
                                        <TableCell colSpan={5} className="text-center py-6 text-muted-foreground text-sm">
                                            No funding records found in the ledger.
                                        </TableCell>
                                    </TableRow>
                                )}
                            </TableBody>
                        </Table>
                    </CardContent>
                </Card>
            </div>
        </PageContainer>
    );
}

import Link from "next/link";
import { MetricCard } from "@/components/cards/metric-card";
import { HorizontalBarChart } from "@/components/donor/transparency-charts";
import { PageContainer } from "@/components/layout/page-container";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import {
    Table,
    TableBody,
    TableCell,
    TableHead,
    TableHeader,
    TableRow,
} from "@/components/ui/table";
import { BadgeCheck, BookOpen, GraduationCap, Wallet } from "lucide-react";
import { createSupabaseServerClient } from "@/lib/supabase/server";
import { getAdminPrograms } from "@/lib/supabase/actions";
import { redirect } from "next/navigation";

export default async function ProgramsManagementPage() {
    const supabase = await createSupabaseServerClient();
    const { data: { user } } = await supabase.auth.getUser();

    if (!user) {
        redirect("/login");
    }

    const programs = await getAdminPrograms();

    const totalBudget = programs.reduce((acc: number, p: any) => acc + (p.total_budget || 0), 0);
    const totalApplicants = 1482; // Future: fetch from summary table/aggregate
    const avgPlacement = programs.length > 0
        ? (programs.reduce((acc: number, p: any) => acc + (p.placement_rate || 0), 0) / programs.length).toFixed(0)
        : "0";

    const programMetrics = [
        { title: "Live Programmes", value: programs.length.toString(), description: "Active or launch-stage tracks", icon: GraduationCap },
        { title: "Programme Demand", value: totalApplicants.toLocaleString(), description: "Applicants across 2026 intake", icon: BookOpen },
        { title: "Average Placement", value: `${avgPlacement}%`, description: "Across established programmes", icon: BadgeCheck },
        { title: "Budget Coverage", value: `N${(totalBudget / 1000000000).toFixed(2)}B`, description: "Tracked across programme portfolios", icon: Wallet },
    ];

    const performanceItems = programs.map((p: any) => ({
        label: p.name,
        value: p.placement_rate || 0,
        color: p.placement_rate > 90 ? "#0f766e" : p.placement_rate > 85 ? "#0284c7" : "#d97706",
    }));

    return (
        <PageContainer
            title="Programs Management"
            description="Manage programme capacity, performance, regional delivery, and budget allocation."
            action={
                <Button asChild>
                    <Link href="/admin/cohorts">Open Cohorts Management</Link>
                </Button>
            }
        >
            <div className="space-y-6">
                <div className="grid gap-4 md:grid-cols-2 xl:grid-cols-4">
                    {programMetrics.map((metric) => (
                        <MetricCard
                            key={metric.title}
                            title={metric.title}
                            value={metric.value}
                            description={metric.description}
                            icon={metric.icon}
                            className="border-border/60"
                        />
                    ))}
                </div>

                <div className="grid gap-6 xl:grid-cols-[1.05fr_0.95fr]">
                    <Card className="border-border/60">
                        <CardHeader>
                            <CardTitle>Program Performance</CardTitle>
                            <CardDescription>Composite score across completion quality and placement outcomes.</CardDescription>
                        </CardHeader>
                        <CardContent>
                            <HorizontalBarChart items={performanceItems} valueSuffix="%" />
                        </CardContent>
                    </Card>

                    <Card className="border-border/60">
                        <CardHeader>
                            <CardTitle>Programme Cards</CardTitle>
                            <CardDescription>Each programme’s capacity, lead, demand, and operating footprint.</CardDescription>
                        </CardHeader>
                        <CardContent className="space-y-4">
                            {programs.map((program: any) => (
                                <div key={program.id} className="rounded-xl border bg-background p-4">
                                    <div className="flex items-start justify-between gap-4">
                                        <div>
                                            <p className="font-medium">{program.name}</p>
                                            <p className="mt-1 text-sm text-muted-foreground">{program.campuses?.join(", ") || "No campuses listed"}</p>
                                        </div>
                                        <span className={`inline-flex rounded-full px-2.5 py-0.5 text-xs font-semibold ${program.status === "active" ? "bg-emerald-100 text-emerald-800" : "bg-amber-100 text-amber-800"}`}>
                                            {program.status}
                                        </span>
                                    </div>
                                    <div className="mt-4 grid gap-3 sm:grid-cols-2">
                                        <div className="rounded-lg bg-muted/20 p-3">
                                            <p className="text-xs uppercase tracking-[0.2em] text-muted-foreground">Lead</p>
                                            <p className="mt-2 font-semibold">{program.program_lead || "Unassigned"}</p>
                                        </div>
                                        <div className="rounded-lg bg-muted/20 p-3">
                                            <p className="text-xs uppercase tracking-[0.2em] text-muted-foreground">Budget</p>
                                            <p className="mt-2 font-semibold">N{(program.total_budget / 1000000).toFixed(0)}M</p>
                                        </div>
                                    </div>
                                </div>
                            ))}
                        </CardContent>
                    </Card>
                </div>

                <Card className="border-border/60">
                    <CardHeader>
                        <CardTitle>Programme Operations Table</CardTitle>
                        <CardDescription>Delivery coverage, applicant demand, and outcomes across the active programme set.</CardDescription>
                    </CardHeader>
                    <CardContent>
                        <Table>
                            <TableHeader>
                                <TableRow>
                                    <TableHead>Programme</TableHead>
                                    <TableHead>Lead</TableHead>
                                    <TableHead>Completion</TableHead>
                                    <TableHead>Placement</TableHead>
                                    <TableHead>Budget</TableHead>
                                </TableRow>
                            </TableHeader>
                            <TableBody>
                                {programs.map((program: any) => (
                                    <TableRow key={program.id}>
                                        <TableCell>
                                            <div>
                                                <p className="font-medium">{program.name}</p>
                                                <p className="text-xs text-muted-foreground">{program.campuses?.join(", ")}</p>
                                            </div>
                                        </TableCell>
                                        <TableCell>{program.program_lead || "—"}</TableCell>
                                        <TableCell>{program.completion_rate || 0}%</TableCell>
                                        <TableCell>{program.placement_rate || 0}%</TableCell>
                                        <TableCell>N{(program.total_budget / 1000000).toFixed(0)}M</TableCell>
                                    </TableRow>
                                ))}
                            </TableBody>
                        </Table>
                    </CardContent>
                </Card>
            </div>
        </PageContainer>
    );
}

import { PageContainer } from "@/components/layout/page-container";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import {
    Table,
    TableBody,
    TableCell,
    TableHead,
    TableHeader,
    TableRow,
} from "@/components/ui/table";
import { Plus, Download, Search, Filter } from "lucide-react";
import { createSupabaseServerClient } from "@/lib/supabase/server";
import { getAdminSponsors } from "@/lib/supabase/actions";
import { redirect } from "next/navigation";

function getSponsorStatusClass(status: string) {
    if (status === "Active") return "bg-emerald-100 text-emerald-800";
    if (status === "Renewal due") return "bg-amber-100 text-amber-800";
    return "bg-red-100 text-red-800";
}

export default async function SponsorsPage() {
    const supabase = await createSupabaseServerClient();
    const { data: { user } } = await supabase.auth.getUser();

    if (!user) {
        redirect("/login");
    }

    const sponsors = await getAdminSponsors();

    return (
        <PageContainer
            title="Sponsors Management"
            description="Manage corporate sponsors, foundations, and institutional donors fueling the platform."
            action={
                <div className="flex gap-3">
                    <Button variant="outline">
                        <Download className="mr-2 h-4 w-4" /> Export
                    </Button>
                    <Button>
                        <Plus className="mr-2 h-4 w-4" /> Add Sponsor
                    </Button>
                </div>
            }
        >
            <div className="space-y-6">
                <Card className="border-border/60">
                    <CardHeader>
                        <div className="flex items-center justify-between">
                            <div>
                                <CardTitle>Sponsor Roster</CardTitle>
                                <CardDescription>Overview of active commitments and reporting statuses.</CardDescription>
                            </div>
                            <div className="flex gap-2">
                                <Button variant="ghost" size="icon"><Search className="h-4 w-4" /></Button>
                                <Button variant="ghost" size="icon"><Filter className="h-4 w-4" /></Button>
                            </div>
                        </div>
                    </CardHeader>
                    <CardContent>
                        <Table>
                            <TableHeader>
                                <TableRow>
                                    <TableHead>Sponsor</TableHead>
                                    <TableHead>Category</TableHead>
                                    <TableHead>Commitment</TableHead>
                                    <TableHead>Focus Area</TableHead>
                                    <TableHead>Renewal</TableHead>
                                    <TableHead>Status</TableHead>
                                </TableRow>
                            </TableHeader>
                            <TableBody>
                                {sponsors.map((sponsor: any) => (
                                    <TableRow key={sponsor.id}>
                                        <TableCell className="font-medium">
                                            {sponsor.first_name} {sponsor.last_name}
                                        </TableCell>
                                        <TableCell>{sponsor.donor_details?.category || "—"}</TableCell>
                                        <TableCell>
                                            {sponsor.donor_details?.commitment
                                                ? `N${(sponsor.donor_details.commitment / 1000000).toFixed(0)}M`
                                                : "—"}
                                        </TableCell>
                                        <TableCell>{sponsor.donor_details?.investment_focus || "—"}</TableCell>
                                        <TableCell>{sponsor.donor_details?.renewal_window || "—"}</TableCell>
                                        <TableCell>
                                            <span className={`inline-flex rounded-full px-2.5 py-0.5 text-xs font-semibold ${getSponsorStatusClass(sponsor.donor_details?.status || "Active")}`}>
                                                {sponsor.donor_details?.status || "Active"}
                                            </span>
                                        </TableCell>
                                    </TableRow>
                                ))}
                                {sponsors.length === 0 && (
                                    <TableRow>
                                        <TableCell colSpan={6} className="text-center py-6 text-muted-foreground text-sm">
                                            No sponsors registered yet.
                                        </TableCell>
                                    </TableRow>
                                )}
                            </TableBody>
                        </Table>
                    </CardContent>
                </Card>
            </div>
        </PageContainer>
    );
}

import Link from "next/link";
import { MetricCard } from "@/components/cards/metric-card";
