function getUserStatusClass(status: string) {
    if (status === "active") return "bg-emerald-100 text-emerald-800";
    if (status === "pending") return "bg-amber-100 text-amber-800";
    return "bg-red-100 text-red-800";
}

export default async function UserManagementPage() {
    const supabase = await createSupabaseServerClient();
    const { data: { user } } = await supabase.auth.getUser();

    if (!user) {
        redirect("/login");
    }

    const allUsers = await getAdminUsers();

    const roleCounts = allUsers.reduce((acc: any, curr: any) => {
        const role = curr.role || "applicant";
        acc[role] = (acc[role] || 0) + 1;
        return acc;
    }, {});

    const userRoleBreakdown = [
        { label: "Applicants", value: roleCounts.applicant || 0, color: "#0f766e" },
        { label: "Scholars", value: roleCounts.scholar || 0, color: "#0284c7" },
        { label: "Reviewers", value: roleCounts.reviewer || 0, color: "#d97706" },
        { label: "Admins", value: roleCounts.admin || 0, color: "#dc2626" },
    ];

    const privilegedUsers = allUsers.filter((u: any) => ["admin", "reviewer", "partner"].includes(u.role));
    const pendingUsers = allUsers.filter((u: any) => u.status === "pending");

    const userMetrics = [
        { title: "Total Users", value: allUsers.length.toString(), description: "All registered accounts", icon: Users },
        { title: "Privileged Access", value: privilegedUsers.length.toString(), description: "Admins, reviewers, partners", icon: Shield },
        { title: "Pending Accounts", value: pendingUsers.length.toString(), description: "Awaiting confirmation", icon: UserCheck },
        { title: "MFA Coverage", value: "92%", description: "Estimated across staff", icon: KeyRound },
    ];

    const displayUsers = allUsers.slice(0, 10); // Show latest 10 for performance

    return (
        <PageContainer
            title="User Management"
            description="Manage platform users, operational roles, access levels, and account state."
            action={
                <Button asChild variant="outline">
                    <Link href="/admin/settings">Open System Settings</Link>
                </Button>
            }
        >
            <div className="space-y-6">
                <div className="grid gap-4 md:grid-cols-2 xl:grid-cols-4">
                    {userMetrics.map((metric) => (
                        <MetricCard
                            key={metric.title}
                            title={metric.title}
                            value={metric.value}
                            description={metric.description}
                            icon={metric.icon}
                            className="border-border/60"
                        />
                    ))}
                </div>

                <div className="grid gap-6 xl:grid-cols-[0.95fr_1.05fr]">
                    <Card className="border-border/60">
                        <CardHeader>
                            <CardTitle>User Role Mix</CardTitle>
                            <CardDescription>Distribution of operational access across platform teams.</CardDescription>
                        </CardHeader>
                        <CardContent>
                            <HorizontalBarChart items={userRoleBreakdown} valueSuffix="" />
                        </CardContent>
                    </Card>

                    <Card className="border-border/60">
                        <CardHeader>
                            <CardTitle>Access Overview</CardTitle>
                            <CardDescription>Role, account type, and current state for core operating accounts.</CardDescription>
                        </CardHeader>
                        <CardContent className="space-y-4">
                            {displayUsers.map((u: any) => (
                                <div key={u.id} className="rounded-xl border bg-background p-4">
                                    <div className="flex items-start justify-between gap-4">
                                        <div>
                                            <p className="font-medium">{u.first_name} {u.last_name}</p>
                                            <p className="mt-1 text-sm text-muted-foreground">{u.role} · {u.email}</p>
                                        </div>
                                        <span className={`inline-flex rounded-full px-2.5 py-0.5 text-xs font-semibold ${getUserStatusClass(u.status)}`}>
                                            {u.status}
                                        </span>
                                    </div>
                                    <p className="mt-3 text-xs uppercase tracking-[0.2em] text-muted-foreground">
                                        Joined {new Date(u.created_at).toLocaleDateString()}
                                    </p>
                                </div>
                            ))}
                        </CardContent>
                    </Card>
                </div>

                <Card className="border-border/60">
                    <CardHeader>
                        <CardTitle>User Directory</CardTitle>
                        <CardDescription>Admin view of account ownership, access scope, and current account status.</CardDescription>
                    </CardHeader>
                    <CardContent>
                        <Table>
                            <TableHeader>
                                <TableRow>
                                    <TableHead>Name</TableHead>
                                    <TableHead>Role</TableHead>
                                    <TableHead>Email</TableHead>
                                    <TableHead>Joined</TableHead>
                                    <TableHead>Status</TableHead>
                                </TableRow>
                            </TableHeader>
                            <TableBody>
                                {displayUsers.map((u: any) => (
                                    <TableRow key={u.id}>
                                        <TableCell className="font-medium">{u.first_name} {u.last_name}</TableCell>
                                        <TableCell className="capitalize">{u.role}</TableCell>
                                        <TableCell>{u.email}</TableCell>
                                        <TableCell>{new Date(u.created_at).toLocaleDateString()}</TableCell>
                                        <TableCell>
                                            <span className={`inline-flex rounded-full px-2.5 py-0.5 text-xs font-semibold ${getUserStatusClass(u.status)}`}>
                                                {u.status}
                                            </span>
                                        </TableCell>
                                    </TableRow>
                                ))}
                            </TableBody>
                        </Table>
                    </CardContent>
                </Card>
            </div>
        </PageContainer>
    );
}

"use client";

import Link from "next/link";
import { useRouter } from "next/navigation";
import { Controller, useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import { z } from "zod";
import { ArrowRight, CircleAlert, Lock, Mail, Shield } from "lucide-react";
import { toast } from "sonner";

import { Alert, AlertDescription, AlertTitle } from "@/components/ui/alert";
import { Button } from "@/components/ui/button";
import {
  FieldGroup,
} from "@/components/ui/field";
import {
  getSafePostLoginRedirectPath,
  resolveUserRoleForSession,
} from "@/lib/auth/roles";
import { getSupabaseBrowserClient } from "@/lib/supabase/client";
import { FormField } from "@/components/forms/form-field";

// ── Schema ────────────────────────────────────────────────────────────────────
const loginSchema = z.object({
  email: z.email("Enter a valid email address."),
  password: z.string().min(1, "Password is required."),
});

type LoginValues = z.infer<typeof loginSchema>;

// ── Component ─────────────────────────────────────────────────────────────────
export default function LoginPage() {
  const router = useRouter();

  const {
    control,
    handleSubmit,
    setError,
    formState: { isSubmitting, errors },
  } = useForm<LoginValues>({
    resolver: zodResolver(loginSchema),
    defaultValues: { email: "", password: "" },
  });

  const onSubmit = async (values: LoginValues) => {
    try {
      const supabase = getSupabaseBrowserClient();
      const { data, error } = await supabase.auth.signInWithPassword({
        email: values.email,
        password: values.password,
      });

      if (error) {
        setError("root", { message: error.message });
        toast.error("Sign-in failed", { description: error.message });
        return;
      }

      if (!data.user) {
        const message =
          "Your account was not returned after sign-in. Please try again.";
        setError("root", { message });
        toast.error("Sign-in failed", { description: message });
        return;
      }

      const role = await resolveUserRoleForSession(supabase, data.user);
      const nextPath = new URLSearchParams(window.location.search).get("next");
      const redirectPath = getSafePostLoginRedirectPath(nextPath, role);

      toast.success("Welcome back!", {
        description: "You have successfully signed in.",
      });
      router.replace(redirectPath);
      router.refresh();
    } catch (err) {
      const message =
        err instanceof Error ? err.message : "Unable to sign you in right now.";
      setError("root", { message });
      toast.error("Authentication error", { description: message });
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center p-4">
      <div className="w-full max-w-3xl grid md:grid-cols-2 border border-border/50 rounded-xl overflow-hidden shadow-sm">
        {/* ── Left: Brand Panel ── */}
        <div className="bg-foreground p-10 flex-col justify-between hidden md:flex">
          <Link href="/" className="flex items-center gap-2.5">
            <div className="h-8 w-8 rounded-md bg-primary flex items-center justify-center shrink-0">
              <span className="text-primary-foreground font-bold text-sm">
                N
              </span>
            </div>
            <span className="text-background font-bold text-sm tracking-tight">
              National Talent Initiative
            </span>
          </Link>

          <div>
            <p className="text-xs font-bold uppercase tracking-widest text-primary flex items-center gap-2 mb-4">
              <span className="inline-block w-5 h-px bg-primary" />
              Secure Portal
            </p>
            <h2 className="text-2xl font-bold leading-snug tracking-tight text-background mb-3">
              Shaping Nigeria&apos;s future,{" "}
              <span className="text-background/50 font-medium">
                one scholar at a time.
              </span>
            </h2>
            <p className="text-sm text-background/45 leading-relaxed">
              Access your dashboard to track applications, funding status, and
              programme milestones.
            </p>
          </div>

          <div className="flex divide-x divide-background/10 border-t border-background/10 pt-5">
            {[
              { value: "5,000+", label: "Scholars" },
              { value: "36", label: "States" },
              { value: "98%", label: "Employed" },
            ].map((s, i) => (
              <div
                key={i}
                className={`flex-1 ${
                  i === 0 ? "pr-4" : i === 2 ? "pl-4" : "px-4"
                }`}
              >
                <div className="text-lg font-bold text-background tracking-tight leading-none">
                  {s.value}
                </div>
                <div className="text-xs text-background/40 mt-1">{s.label}</div>
              </div>
            ))}
          </div>
        </div>

        {/* ── Right: Form Panel ── */}
        <div className="bg-background p-8 md:p-10 flex flex-col justify-center gap-6">
          {/* Mobile logo */}
          <Link href="/" className="flex md:hidden items-center gap-2">
            <div className="h-7 w-7 rounded-md bg-primary flex items-center justify-center">
              <span className="text-primary-foreground font-bold text-xs">
                N
              </span>
            </div>
            <span className="font-bold text-sm tracking-tight">
              National Talent Initiative
            </span>
          </Link>

          <div>
            <p className="text-xs font-bold uppercase tracking-widest text-muted-foreground mb-1">
              Welcome back
            </p>
            <h1 className="text-xl font-bold tracking-tight">
              Sign in to your portal
            </h1>
          </div>

          {/* Root / server error */}
          {errors.root && (
            <Alert variant="destructive">
              <CircleAlert className="h-4 w-4" />
              <AlertTitle>Sign-in failed</AlertTitle>
              <AlertDescription>{errors.root.message}</AlertDescription>
            </Alert>
          )}

          <form onSubmit={handleSubmit(onSubmit)}>
            <FieldGroup className="space-y-4">
              <FormField
                name="email"
                control={control}
                label="Email address"
                type="email"
                placeholder="you@example.com"
                autoComplete="email"
                icon={Mail}
              />

              <FormField
                name="password"
                control={control}
                label={
                  <div className="flex items-center justify-between w-full">
                    <span>Password</span>
                    <Link
                      href="/forgot-password"
                      className="text-xs text-primary hover:underline"
                    >
                      Forgot password?
                    </Link>
                  </div>
                }
                isPassword
                placeholder="••••••••"
                autoComplete="current-password"
                icon={Lock}
              />

              <Button
                type="submit"
                className="w-full h-9 text-sm rounded-md gap-2 mt-1"
                disabled={isSubmitting}
              >
                {isSubmitting ? "Signing in..." : "Sign in to Portal"}
                <ArrowRight className="h-3.5 w-3.5" />
              </Button>
            </FieldGroup>
          </form>

          {/* Security note */}
          <div className="flex items-start gap-2.5 border-t border-border/50 pt-5">
            <Shield className="h-3.5 w-3.5 shrink-0 mt-0.5 text-primary" />
            <p className="text-xs text-muted-foreground leading-relaxed">
              End-to-end encrypted. Never share your password with anyone,
              including NTDI staff.
            </p>
          </div>

          {/* Footer */}
          <div className="space-y-2">
            <p className="text-xs text-muted-foreground">
              No account?{" "}
              <Link
                href="/signup"
                className="text-foreground font-semibold hover:underline"
              >
                Create one
              </Link>
            </p>
            <p className="text-xs text-muted-foreground">
              By signing in you agree to our{" "}
              <Link href="/terms" className="hover:underline">
                Terms
              </Link>{" "}
              and{" "}
              <Link href="/privacy" className="hover:underline">
                Privacy Policy
              </Link>
              .
            </p>
          </div>
        </div>
      </div>
    </div>
  );
}

import { MetricCard } from "@/components/cards/metric-card";
import { PageContainer } from "@/components/layout/page-container";
import { Avatar, AvatarFallback } from "@/components/ui/avatar";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Card, CardContent } from "@/components/ui/card";
import { Progress } from "@/components/ui/progress";
import { Award, BookOpen, Briefcase, Users } from "lucide-react";
import { createSupabaseServerClient } from "@/lib/supabase/server";
import { getDonorDashboardData } from "@/lib/supabase/actions";
import { redirect } from "next/navigation";

export default async function SponsoredScholarsPage() {
    const supabase = await createSupabaseServerClient();
    const { data: { user } } = await supabase.auth.getUser();

    if (!user) {
        redirect("/login");
    }

    const { sponsoredScholars } = await getDonorDashboardData(user.id);

    const averageProgress = sponsoredScholars.length > 0
        ? Math.round(sponsoredScholars.reduce((sum: number, scholar: any) => sum + (scholar.progress_score || 0), 0) / sponsoredScholars.length)
        : 0;

    const strongPerformers = sponsoredScholars.filter((scholar: any) => (scholar.progress_score || 0) >= 80).length;

    return (
        <PageContainer
            title="Sponsored Scholars"
            description="Track scholar progress, funding usage, and development outcomes for the scholars supported by your contribution."
            action={<Button>Export Scholar Summary</Button>}
        >
            <div className="space-y-6">
                <div className="grid gap-4 md:grid-cols-3">
                    <MetricCard title="Sponsored Scholars" value={sponsoredScholars.length} description="Currently covered by your funding" icon={Users} />
                    <MetricCard title="Average Progress" value={`${averageProgress}%`} description="Combined academic and development score" icon={Award} />
                    <MetricCard title="Strong Performers" value={strongPerformers} description="Scholars at or above 80% progress" icon={BookOpen} />
                </div>

                <div className="grid gap-4 xl:grid-cols-2">
                    {sponsoredScholars.map((scholar: any) => (
                        <Card key={scholar.id} className="border-border/60">
                            <CardContent className="p-5">
                                <div className="flex items-start gap-4">
                                    <Avatar className="h-14 w-14">
                                        <AvatarFallback className="bg-primary/10 font-semibold text-primary">
                                            {scholar.first_name?.[0] ?? ''}{scholar.last_name?.[0] ?? ''}
                                            {!scholar.first_name && !scholar.last_name ? '?' : ''}
                                        </AvatarFallback>
                                    </Avatar>
                                    <div className="flex-1 space-y-3">
                                        <div className="flex flex-wrap items-start justify-between gap-3">
                                            <div>
                                                <div className="flex flex-wrap items-center gap-2">
                                                    <h2 className="font-semibold">
                                                        {scholar.first_name || scholar.last_name
                                                            ? `${scholar.first_name ?? ''} ${scholar.last_name ?? ''}`.trim()
                                                            : "Name unavailable"}
                                                    </h2>
                                                    <Badge variant="outline">Cohort {scholar.cohort || "Unknown"}</Badge>
                                                </div>
                                                <p className="mt-1 text-sm text-muted-foreground">{scholar.program || "Not provided"}</p>
                                                <p className="text-sm text-muted-foreground">{scholar.institution || "Not provided"}</p>
                                            </div>
                                            <Badge className={(scholar.progress_score || 0) >= 80 ? "bg-emerald-100 text-emerald-800 hover:bg-emerald-100" : "bg-blue-100 text-blue-800 hover:bg-blue-100"}>
                                                {(scholar.progress_score || 0) >= 80 ? "Excellent" : "On Track"}
                                            </Badge>
                                        </div>

                                        <div className="space-y-2">
                                            <div className="flex items-center justify-between text-sm">
                                                <span className="text-muted-foreground">Development progress</span>
                                                <span className="font-semibold">{scholar.progress_score || 0}%</span>
                                            </div>
                                            <Progress value={scholar.progress_score || 0} className="h-2" />
                                        </div>

                                        <div className="grid gap-3 sm:grid-cols-2">
                                            <div className="rounded-xl border bg-muted/20 p-4">
                                                <p className="text-xs uppercase tracking-[0.2em] text-muted-foreground">Funding</p>
                                                <p className="mt-2 font-semibold">Allocated</p>
                                                <p className="text-xs text-muted-foreground">Direct scholar support</p>
                                            </div>
                                            <div className="rounded-xl border bg-muted/20 p-4">
                                                <p className="text-xs uppercase tracking-[0.2em] text-muted-foreground">Placement Track</p>
                                                <p className="mt-2 font-semibold">{scholar.placement_status === "placed" ? "Deployment Ready" : "In Selection"}</p>
                                            </div>
                                        </div>

                                        <div className="rounded-xl border bg-background p-4">
                                            <p className="flex items-center gap-2 text-sm font-medium">
                                                <Briefcase className="h-4 w-4 text-primary" />
                                                Impact Narrative
                                            </p>
                                            <p className="mt-2 text-sm text-muted-foreground">
                                                {scholar.bio || "No impact narrative available."}
                                            </p>
                                        </div>
                                    </div>
                                </div>
                            </CardContent>
                        </Card>
                    ))}
                    {sponsoredScholars.length === 0 && (
                        <div className="col-span-full py-20 text-center border-2 border-dashed rounded-2xl">
                            <Users className="h-10 w-10 text-muted-foreground mx-auto mb-4" />
                            <p className="text-muted-foreground">No sponsored scholars currently assigned to your portfolio.</p>
                        </div>
                    )}
                </div>
            </div>
        </PageContainer>
    );
}

