];

function wordCount(text: string) {
  return text.trim() === "" ? 0 : text.trim().split(/\s+/).length;
}

export function EssayForm({ application, onNext, onBack }: EssayFormProps) {
  const router = useRouter();
  const [loading, setLoading] = useState(false);
  const essays = application?.essays || {};
  const [formData, setFormData] = useState(essays);

  const handleTextChange = (id: string, value: string) => {
    setFormData((prev: any) => ({ ...prev, [id]: value }));
  };

  const handleSave = async (
    e: React.FormEvent | React.MouseEvent<HTMLButtonElement>,
    isNext = false
  ) => {
    e.preventDefault();
    for (const essay of essayPrompts) {
      const count = wordCount(formData[essay.id] || "");
      if (count < essay.wordMin) {
        toast.error(
          `"${essay.label}" needs at least ${essay.wordMin} words (${count} written).`
        );
        return;
      }
      if (count > essay.wordMax) {
        toast.error(
          `"${essay.label}" exceeds the ${essay.wordMax}-word limit (${count} written).`
        );
        return;
      }
    }
    setLoading(true);
    try {
      const { error } = await saveApplicationStep(3, formData, isNext);
      if (error) {
        toast.error(error);
        return;
      }
      toast.success("Draft saved");
      if (isNext) {
        if (onNext) onNext();
        else router.push("/application/step-4");
      }
      else router.refresh();
    } catch {
      toast.error("Failed to save progress. Please try again.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="max-w-3xl mx-auto space-y-5">
      {/* Warning banner */}
      <div className="flex items-center gap-2.5 px-4 py-3 bg-muted/30 border border-border/50 rounded-xl text-xs text-muted-foreground">
        <AlertCircle className="h-3.5 w-3.5 text-amber-500 shrink-0" />
        Do not copy content from the internet or use AI-generated text.
        Plagiarism is grounds for immediate disqualification.
      </div>

      <form onSubmit={(e) => handleSave(e, true)}>
        <div className="space-y-4">
          {essayPrompts.map((essay, i) => {
            const content = formData[essay.id] || "";
            const count = wordCount(content);
            const isStarted = count > 0;
            const isOver = count > essay.wordMax;
            const isUnder = count < essay.wordMin;

            return (
              <div
                key={essay.id}
                className="border border-border/50 rounded-xl overflow-hidden"
              >
                {/* Header */}
                <div className="flex items-start justify-between gap-3 px-5 py-4 border-b border-border/50">
                  <div>
                    <div className="flex items-center gap-2 mb-1">
                      <span className="text-[10px] font-bold uppercase tracking-widest text-muted-foreground">
                        Essay {i + 1}
                      </span>
                      {isStarted && (
                        <span className="inline-flex items-center gap-1 text-[10px] font-medium bg-green-50 dark:bg-green-950/30 text-green-700 dark:text-green-400 rounded-full px-2 py-px border border-green-200/50 dark:border-green-800/30">
                          <CheckCircle2 className="h-2.5 w-2.5" /> Draft saved
                        </span>
                      )}
                    </div>
                    <h3 className="text-sm font-semibold">{essay.label}</h3>
                  </div>
                  <span className="text-[10px] text-muted-foreground bg-muted/50 border border-border/50 rounded-md px-2 py-1 shrink-0 whitespace-nowrap">
                    {essay.wordMin}–{essay.wordMax} words
                  </span>
                </div>

                {/* Prompt */}
                <div className="px-5 py-3.5 bg-muted/20 border-b border-border/50">
                  <p className="text-xs text-muted-foreground leading-relaxed">
                    {essay.prompt}
                  </p>
                </div>

                {/* Textarea */}
                <div className="p-5 space-y-2">
                  <Label htmlFor={essay.id} className="sr-only">
                    {essay.label}
                  </Label>
                  <Textarea
                    id={essay.id}
                    value={content}
                    onChange={(e) => handleTextChange(essay.id, e.target.value)}
                    placeholder={`Begin your response here… (minimum ${essay.wordMin} words)`}
                    className="min-h-[180px] resize-y text-sm leading-relaxed"
                  />
                  <div className="flex items-center justify-between text-[11px] text-muted-foreground">
                    <span>Auto-saved as you type</span>
                    <span
                      className={cn(
                        "font-medium",
                        isOver
                          ? "text-red-500"
                          : isUnder && isStarted
                            ? "text-amber-500"
                            : !isUnder
                              ? "text-green-600 dark:text-green-400"
                              : ""
                      )}
                    >
                      {count} / {essay.wordMin}–{essay.wordMax} words
                    </span>
                  </div>
                </div>
              </div>
            );
          })}
        </div>

        {/* Footer */}
        <div className="flex items-center justify-between mt-4 px-5 py-3.5 border border-border/50 rounded-xl bg-muted/20">
          <div className="flex gap-2">
            {onBack ? (
              <Button
                type="button"
                variant="outline"
                size="sm"
                className="gap-2 rounded-md"
                onClick={onBack}
              >
                <ArrowLeft className="h-3.5 w-3.5" /> Back
              </Button>
            ) : (
              <Link href="/application/step-2">
                <Button
                  type="button"
                  variant="outline"
                  size="sm"
                  className="gap-2 rounded-md"
                >
                  <ArrowLeft className="h-3.5 w-3.5" /> Back
                </Button>
              </Link>
            )}
            <Button
              type="button"
              variant="ghost"
              size="sm"
              className="gap-2 rounded-md"
              onClick={(e) => handleSave(e, false)}
              disabled={loading}
            >
              <Save className="h-3.5 w-3.5" /> Save Draft
            </Button>
          </div>
          <Button
            type="submit"
            size="sm"
            className="gap-2 rounded-md"
            disabled={loading}
          >
            {loading ? "Saving..." : "Save & Continue"}{" "}
            <ArrowRight className="h-3.5 w-3.5" />
          </Button>
        </div>
      </form>
    </div>
  );
}

"use client";

import React from "react";
import { Controller } from "react-hook-form";
import { Input } from "@/components/ui/input";
import { Field, FieldError, FieldLabel } from "@/components/ui/field";
import { cn } from "@/lib/utils";
import type { LucideIcon } from "lucide-react";
import { Eye, EyeOff } from "lucide-react";

type BaseProps = {
  name: string;
  control: any;
  label?: React.ReactNode;
  icon?: LucideIcon;
  className?: string;
};

/* ─────────────────────────────────────────────
   TEXT / PASSWORD INPUT
───────────────────────────────────────────── */
type InputProps = BaseProps & {
  type?: "text" | "email" | "password";
  placeholder?: string;
  autoComplete?: string;
  isPassword?: boolean;
};

/* ─────────────────────────────────────────────
   CHECKBOX
───────────────────────────────────────────── */
type CheckboxProps = BaseProps & {
  type: "checkbox";
};

type Props = InputProps | CheckboxProps;

export function FormField(props: Props) {
  const { name, control, label, icon: Icon } = props as BaseProps;

  const isCheckbox = props.type === "checkbox";
  const isPassword = (props as InputProps).isPassword;

  const [visible, setVisible] = React.useState(false);

  return (
    <Controller
      name={name}
      control={control}
      render={({ field, fieldState }) => (
        <Field data-invalid={fieldState.invalid}>
          {/* ───────── LABEL ───────── */}
          {label && !isCheckbox && (
            <FieldLabel htmlFor={name} className="text-xs">
              {label}
            </FieldLabel>
          )}

          {/* ───────── CHECKBOX ───────── */}
          {isCheckbox ? (
            <div className="flex items-start gap-3 pt-0.5">
              <input
                id={name}
                type="checkbox"
                checked={field.value}
                onChange={field.onChange}
                className="mt-1 accent-primary"
              />

              <label
                htmlFor={name}
                className="text-[11px] text-muted-foreground leading-relaxed cursor-pointer"
              >
                {label}
              </label>

              {fieldState.invalid && (
                <FieldError
                  errors={[fieldState.error]}
                  className="text-xs mt-1"
                />
              )}
            </div>
          ) : (
            /* ───────── INPUTS ───────── */
            <div className="relative">
              {Icon && (
                <Icon className="absolute left-3 top-2.5 h-3.5 w-3.5 text-muted-foreground" />
              )}

              <Input
                {...field}
                id={name}
                type={
                  isPassword
                    ? visible
                      ? "text"
                      : "password"
                    : props.type || "text"
                }
                placeholder={(props as InputProps).placeholder}
                autoComplete={(props as InputProps).autoComplete}
                className={cn(
                  "h-9 text-sm",
                  Icon && "pl-8",
                  isPassword && "pr-10"
                )}
                aria-invalid={fieldState.invalid}
              />

              {/* PASSWORD TOGGLE */}
              {isPassword && (
                <button
                  type="button"
                  onClick={() => setVisible((v) => !v)}
                  className="absolute right-3 top-2.5 text-muted-foreground hover:text-foreground transition"
                  aria-label={visible ? "Hide password" : "Show password"}
                >
                  {visible ? <EyeOff size={14} /> : <Eye size={14} />}
                </button>
              )}

              {fieldState.invalid && (
                <FieldError errors={[fieldState.error]} className="text-xs" />
              )}
            </div>
          )}
        </Field>
      )}
    />
  );
}

"use client";

import { useState } from "react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import { Separator } from "@/components/ui/separator";
import { Badge } from "@/components/ui/badge";
import {
  Save,
  User,
  Mail,
  Phone,
  MapPin,
  Shield,
  Bell,
  Lock,
  AlertTriangle,
} from "lucide-react";
import { nigerianStates } from "@/constants/nigeria";
import { toast } from "sonner";
import {
  changePassword,
  withdrawApplication,
  updateProfile,
} from "@/lib/supabase/actions";
import { CldUploadWidget } from "next-cloudinary";

interface ProfileFormProps {
  profile: any;
}

const NOTIFICATION_PREFS = [
  {
    key: "app_status",
    label: "Application Status Updates",
    desc: "Notify me when my application status changes.",
    enabled: true,
  },
  {
    key: "doc_verify",
    label: "Document Verification",
    desc: "Notify me when a document is verified or flagged.",
    enabled: true,
  },
  {
    key: "announcements",
    label: "New Announcements",
    desc: "Receive announcements from the programme office.",
    enabled: true,
  },
  {
    key: "deadlines",
    label: "Deadline Reminders",
    desc: "Remind me before important deadlines.",
    enabled: false,
  },
];

export function ProfileForm({ profile }: ProfileFormProps) {
  const [loading, setLoading] = useState(false);

  // ── Profile field state (controlled) ─────────────────────────────────────
  const [firstName, setFirstName] = useState(profile?.first_name ?? "");
  const [lastName, setLastName] = useState(profile?.last_name ?? "");
  const [phone, setPhone] = useState(profile?.phone ?? "");
  const [stateOfOrigin, setStateOfOrigin] = useState(
    profile?.state_of_origin ?? ""
  );
  const [avatarUrl, setAvatarUrl] = useState(profile?.avatar_url ?? "");

  // ── Notification Preferences ──────────────────────────────────────────────
  const [prefs, setPrefs] = useState<Record<string, boolean>>(
    Object.fromEntries(NOTIFICATION_PREFS.map((p) => [p.key, p.enabled]))
  );
  const [prefsLoading, setPrefsLoading] = useState(false);

  const savePreferences = async () => {
    setPrefsLoading(true);
    // Optimistic save — upgrade to DB persist once notification_preferences table exists
    await new Promise((r) => setTimeout(r, 600));
    setPrefsLoading(false);
    toast.success("Notification preferences saved");
  };

  // ── Password Change ───────────────────────────────────────────────────────
  const [currentPw, setCurrentPw] = useState("");
  const [newPw, setNewPw] = useState("");
  const [confirmPw, setConfirmPw] = useState("");
  const [pwLoading, setPwLoading] = useState(false);

  const handleChangePassword = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!currentPw || !newPw || !confirmPw) {
      toast.error("All password fields are required");
      return;
    }
    if (newPw.length < 8) {
      toast.error("New password must be at least 8 characters");
      return;
    }
    if (newPw !== confirmPw) {
      toast.error("Passwords do not match");
      return;
    }
    setPwLoading(true);
    const { error } = await changePassword(newPw);
    setPwLoading(false);
    if (error) {
      toast.error(error);
    } else {
      toast.success("Password updated successfully");
      setCurrentPw("");
      setNewPw("");
      setConfirmPw("");
    }
  };

  // ── Withdraw Application ──────────────────────────────────────────────────
  const [showWithdrawConfirm, setShowWithdrawConfirm] = useState(false);
  const [withdrawing, setWithdrawing] = useState(false);

  const handleWithdraw = async () => {
    setWithdrawing(true);
    const { error } = await withdrawApplication(profile.id);
    setWithdrawing(false);
    setShowWithdrawConfirm(false);
    if (error) {
      toast.error(error);
    } else {
      toast.success("Your application has been withdrawn");
    }
  };

  // ── Profile Save ──────────────────────────────────────────────────────────
  const handleSaveProfile = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    try {
      const { error } = await updateProfile(profile.id, {
        first_name: firstName,
        last_name: lastName,
        phone,
        state_of_origin: stateOfOrigin,
        avatar_url: avatarUrl,
      });
      if (error) {
        toast.error(error);
      } else {
        toast.success("Profile updated successfully");
        window.dispatchEvent(new Event("profileUpdated"));
      }
    } catch (err) {
      toast.error("An unexpected error occurred. Please try again.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="max-w-3xl mx-auto space-y-6">
      {/* ── Personal Information ── */}
      <Card className="border-border/50">
        <CardHeader className="border-b bg-muted/10 pb-4">
          <div className="flex items-center gap-4">
            <div className="h-16 w-16 rounded-full bg-primary/10 flex items-center justify-center text-2xl font-bold text-primary relative group overflow-hidden shrink-0">
              {avatarUrl ? (
                <img
                  src={avatarUrl}
                  alt="Avatar"
                  className="w-full h-full object-cover"
                />
              ) : (
                <span>
                  {profile.first_name?.[0] ?? ""}
                  {profile.last_name?.[0] ?? ""}
                </span>
              )}
              <CldUploadWidget
                signatureEndpoint="/api/cloudinary/sign"
                onSuccess={(result) => {
                  if (
                    result.info &&
                    typeof result.info !== "string" &&
                    result.info.secure_url
                  ) {
                    setAvatarUrl(result.info.secure_url);
                    updateProfile(profile.id, {
                      avatar_url: result.info.secure_url,
                    }).then(({ error }) => {
                      if (error) {
                        toast.error("Failed to save avatar. Please try again.");
                      } else {
                        toast.success("Avatar updated successfully!");
                        window.dispatchEvent(new Event("profileUpdated"));
                      }
                    });
                  }
                }}
              >
                {({ open }) => (
                  <div
                    onClick={(e) => {
                      e.preventDefault();
                      open();
                    }}
                    className="absolute inset-0 bg-black/50 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity cursor-pointer text-white text-xs font-medium"
                  >
                    Edit
                  </div>
                )}
              </CldUploadWidget>
            </div>
            <div>
              <h2 className="text-lg font-bold">
                {profile.first_name ?? ""} {profile.last_name ?? ""}
              </h2>
              <p className="text-sm text-muted-foreground">
                {profile.email ?? ""}
              </p>
              <Badge variant="secondary" className="mt-1 text-xs uppercase">
                {profile.role ?? "user"} Account
              </Badge>
            </div>
          </div>
        </CardHeader>

        <CardContent className="p-6 space-y-6">
          <form onSubmit={handleSaveProfile} className="space-y-6">
            <div className="space-y-4">
              <h3 className="text-sm font-semibold uppercase tracking-wider text-muted-foreground flex items-center gap-2">
                <User className="h-4 w-4" /> Personal Information
              </h3>
              <div className="grid sm:grid-cols-2 gap-4">
                <div className="space-y-2">
                  <Label htmlFor="first">First Name</Label>
                  <Input
                    id="first"
                    value={firstName}
                    onChange={(e) => setFirstName(e.target.value)}
                  />
                </div>
                <div className="space-y-2">
                  <Label htmlFor="last">Last Name</Label>
                  <Input
                    id="last"
                    value={lastName}
                    onChange={(e) => setLastName(e.target.value)}
                  />
                </div>
              </div>
            </div>

            <Separator />

            <div className="space-y-4">
              <h3 className="text-sm font-semibold uppercase tracking-wider text-muted-foreground flex items-center gap-2">
                <Mail className="h-4 w-4" /> Contact Details
              </h3>
              <div className="space-y-2">
                <Label htmlFor="email">Email Address</Label>
                <Input
                  id="email"
                  type="email"
                  defaultValue={profile.email}
                  disabled
                />
                <p className="text-xs text-muted-foreground">
                  Email changes are restricted for security. Contact support.
                </p>
              </div>
              <div className="space-y-2">
                <Label htmlFor="phone">Phone Number</Label>
                <div className="relative">
                  <Phone className="absolute left-3 top-2.5 h-4 w-4 text-muted-foreground" />
                  <Input
                    id="phone"
                    type="tel"
                    value={phone}
                    onChange={(e) => setPhone(e.target.value)}
                    className="pl-9"
                  />
                </div>
              </div>
            </div>

            <Separator />

            <div className="space-y-4">
              <h3 className="text-sm font-semibold uppercase tracking-wider text-muted-foreground flex items-center gap-2">
                <MapPin className="h-4 w-4" /> State of Origin
              </h3>
              <Select value={stateOfOrigin} onValueChange={setStateOfOrigin}>
                <SelectTrigger>
                  <SelectValue />
                </SelectTrigger>
                <SelectContent>
                  {nigerianStates.map((s) => (
                    <SelectItem key={s} value={s}>
                      {s}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>

            <div className="flex justify-end">
              <Button type="submit" className="gap-2" disabled={loading}>
                <Save className="h-4 w-4" />{" "}
                {loading ? "Saving..." : "Save Profile Changes"}
              </Button>
            </div>
          </form>
        </CardContent>
      </Card>

      {/* ── Notification Preferences ── */}
      <Card className="border-border/50">
        <CardHeader className="border-b pb-3 bg-muted/10">
          <CardTitle className="text-sm font-semibold flex items-center gap-2">
            <Bell className="h-4 w-4" /> Notification Preferences
          </CardTitle>
        </CardHeader>
        <CardContent className="p-6 space-y-4">
          {NOTIFICATION_PREFS.map((pref) => (
            <div
              key={pref.key}
              className="flex items-start justify-between gap-4"
            >
              <div>
                <p className="text-sm font-medium">{pref.label}</p>
                <p className="text-xs text-muted-foreground">{pref.desc}</p>
              </div>
              <input
                type="checkbox"
                id={`pref-${pref.key}`}
                checked={prefs[pref.key]}
                onChange={(e) =>
                  setPrefs((prev) => ({
                    ...prev,
                    [pref.key]: e.target.checked,
                  }))
                }
                className="mt-1 h-4 w-4 accent-primary shrink-0 cursor-pointer"
              />
            </div>
          ))}
          <div className="flex justify-end pt-2">
            <Button
              variant="outline"
              className="gap-2"
              onClick={savePreferences}
              disabled={prefsLoading}
            >
              <Save className="h-4 w-4" />
              {prefsLoading ? "Saving..." : "Save Preferences"}
            </Button>
          </div>
        </CardContent>
      </Card>

      {/* ── Account Security ── */}
      <Card className="border-border/50">
        <CardHeader className="border-b pb-3 bg-muted/10">
          <CardTitle className="text-sm font-semibold flex items-center gap-2">
            <Shield className="h-4 w-4" /> Account Security
          </CardTitle>
        </CardHeader>
        <CardContent className="p-6 space-y-4">
          <form onSubmit={handleChangePassword} className="space-y-4">
            <div className="space-y-2">
              <Label htmlFor="cur-pw">Current Password</Label>
              <div className="relative">
                <Lock className="absolute left-3 top-2.5 h-4 w-4 text-muted-foreground" />
                <Input
                  id="cur-pw"
                  type="password"
                  className="pl-9"
                  placeholder="••••••••"
                  value={currentPw}
                  onChange={(e) => setCurrentPw(e.target.value)}
                />
              </div>
            </div>
            <div className="grid sm:grid-cols-2 gap-4">
              <div className="space-y-2">
                <Label htmlFor="new-pw">New Password</Label>
                <div className="relative">
                  <Lock className="absolute left-3 top-2.5 h-4 w-4 text-muted-foreground" />
                  <Input
                    id="new-pw"
                    type="password"
                    className="pl-9"
                    placeholder="Minimum 8 characters"
                    value={newPw}
                    onChange={(e) => setNewPw(e.target.value)}
                  />
                </div>
              </div>
              <div className="space-y-2">
                <Label htmlFor="confirm-pw">Confirm Password</Label>
                <Input
                  id="confirm-pw"
                  type="password"
                  placeholder="Re-enter password"
                  value={confirmPw}
                  onChange={(e) => setConfirmPw(e.target.value)}
                />
              </div>
            </div>
            <div className="flex justify-end pt-1">
              <Button
                type="submit"
                variant="outline"
                className="gap-2"
                disabled={pwLoading}
              >
                <Lock className="h-4 w-4" />
                {pwLoading ? "Updating..." : "Update Password"}
              </Button>
            </div>
          </form>
        </CardContent>
      </Card>

      {/* ── Danger Zone ── */}
      <Card className="border-red-200 bg-red-50/30 dark:bg-red-900/10">
        <CardContent className="p-5 flex flex-col sm:flex-row sm:items-center sm:justify-between gap-4">
          <div>
            <p className="font-semibold text-sm text-red-700">
              Withdraw Application
            </p>
            <p className="text-xs text-muted-foreground mt-0.5">
              This will permanently withdraw your application. This action
              cannot be undone.
            </p>
          </div>
          <Button
            variant="destructive"
            size="sm"
            className="shrink-0"
            onClick={() => setShowWithdrawConfirm(true)}
            disabled={withdrawing}
          >
            Withdraw Application
          </Button>
        </CardContent>

        {showWithdrawConfirm && (
          <CardContent className="px-5 pb-5 pt-0 border-t border-red-200">
            <div className="rounded-md bg-red-100/70 dark:bg-red-900/20 border border-red-300 dark:border-red-700 p-4 space-y-3">
              <div className="flex items-start gap-3">
                <AlertTriangle className="h-5 w-5 text-red-600 shrink-0 mt-0.5" />
                <div>
                  <p className="text-sm font-semibold text-red-700">
                    Are you sure?
                  </p>
                  <p className="text-xs text-red-600 mt-0.5">
                    This will immediately withdraw your application. You will
                    not be able to reverse this.
                  </p>
                </div>
              </div>
              <div className="flex gap-3 justify-end">
                <Button
                  variant="outline"
                  size="sm"
                  onClick={() => setShowWithdrawConfirm(false)}
                  disabled={withdrawing}
                >
                  Cancel
                </Button>
                <Button
                  variant="destructive"
                  size="sm"
                  onClick={handleWithdraw}
                  disabled={withdrawing}
                >
                  {withdrawing ? "Withdrawing..." : "Confirm Withdraw"}
                </Button>
              </div>
            </div>
          </CardContent>
        )}
      </Card>
    </div>
  );
}

"use server";

import type { SupabaseClient } from "@supabase/supabase-js";
import { createSupabaseAdminClient } from "./admin";
import { createSupabaseServerClient } from "./server";
import {
    Scholar,
    Milestone,
    Announcement,
    ImpactMetric,
    FundingRecord,
    ApplicationStatus,
    DocumentStatus,
    DocumentType,
    UploadedDocument,
} from "@/types";

const MS_PER_DAY = 1000 * 60 * 60 * 24;
type ServerSupabaseClient = Awaited<ReturnType<typeof createSupabaseServerClient>>;
type PublicSupabaseClient = SupabaseClient<any, "public", any>;

function getProgramName(program: unknown): string {
    if (!program || typeof program !== "object") return "";

    const source = program as Record<string, unknown>;
    const name = typeof source.name === "string" ? source.name.trim() : "";
    if (name) return name;

    return typeof source.title === "string" ? source.title.trim() : "";
}

function normalizeProgramRecord<T>(program: T): T {
    const normalizedName = getProgramName(program);

    if (!program || typeof program !== "object" || !normalizedName) {
        return program;
    }

    const source = program as Record<string, unknown>;
    if (typeof source.name === "string" && source.name.trim().length > 0) {
        return program;
    }

    return {
        ...source,
        name: normalizedName,
    } as T;
}

function normalizeProgramsList<T>(programs: T[] | null | undefined): T[] {
    return (programs || []).map((program) => normalizeProgramRecord(program));
}

function normalizeProgramsRelation<T>(rows: T[] | null | undefined): T[] {
    return (rows || []).map((row) => {
        if (!row || typeof row !== "object") {
            return row;
        }

        const source = row as Record<string, unknown>;
        if (!source.programs || typeof source.programs !== "object") {
            return row;
        }

        return {
            ...source,
            programs: normalizeProgramRecord(source.programs),
        } as T;
    });
}

function getNumericValue(value: unknown): number | null {
    if (typeof value === "number" && Number.isFinite(value)) {
        return value;
    }

    if (typeof value === "string") {
        const trimmedValue = value.trim();
        if (!trimmedValue) {
            return null;
        }

        const parsedValue = Number(trimmedValue);
        return Number.isFinite(parsedValue) ? parsedValue : null;
    }

    return null;
}

function getTrimmedString(value: unknown): string | null {
    if (typeof value !== "string") {
        return null;
    }

    const trimmedValue = value.trim();
    return trimmedValue ? trimmedValue : null;
}

function normalizeCohortRecord<T>(cohort: T): T {
    if (!cohort || typeof cohort !== "object") {
        return cohort;
    }

    const source = cohort as Record<string, unknown>;
    const normalizedPrograms =
        source.programs && typeof source.programs === "object"
            ? normalizeProgramRecord(source.programs)
            : null;
    const reviewCompletionPercentage =
        getNumericValue(source.review_completion_percentage) ??
        getNumericValue(source.review_completion) ??
        0;
    const fundingReleased =
        getNumericValue(source.funding_released) ??
        0;
    const readinessStatus =
        getTrimmedString(source.readiness_status) ??
        getTrimmedString(source.readiness) ??
        "planned";

    return {
        ...source,
        programs: normalizedPrograms,
        review_completion_percentage: reviewCompletionPercentage,
        funding_released: fundingReleased,
        readiness_status: readinessStatus,
    } as T;
}

function normalizeCohortsList<T>(rows: T[] | null | undefined): T[] {
    return (rows || []).map((row) => normalizeCohortRecord(row));
}

function isMissingRelationshipError(error: unknown, fromTable: string, toTable: string): boolean {
    if (!error || typeof error !== "object") {
        return false;
    }

    const source = error as Record<string, unknown>;
    const message = typeof source.message === "string" ? source.message : "";
    const details = typeof source.details === "string" ? source.details : "";

    if (source.code !== "PGRST200") {
        return false;
    }

    return (
        (message.includes(`'${fromTable}'`) && message.includes(`'${toTable}'`)) ||
        (details.includes(`'${fromTable}'`) && details.includes(`'${toTable}'`))
    );
}

function isTablePermissionError(error: unknown, table: string): boolean {
    if (!error || typeof error !== "object") {
        return false;
    }

    const source = error as Record<string, unknown>;
    const message = typeof source.message === "string"
        ? source.message.toLocaleLowerCase()
        : "";

    return source.code === "42501" && message.includes(`permission denied for table ${table.toLocaleLowerCase()}`);
}

async function runWithTablePermissionFallback<T>(
    supabase: ServerSupabaseClient,
    table: string,
    query: (client: PublicSupabaseClient) => Promise<{ data: T; error: unknown }>
): Promise<{ data: T; error: unknown }> {
    const primaryResult = await query(supabase);

    if (!isTablePermissionError(primaryResult.error, table)) {
        return primaryResult;
    }

    return await query(createSupabaseAdminClient());
}

async function getCohortYearMap(
    supabase: ServerSupabaseClient,
    cohortIds: Array<string | null | undefined>
): Promise<Map<string, string | number | null>> {
    const uniqueCohortIds = Array.from(
        new Set(
            cohortIds
                .map((cohortId) => getTrimmedString(cohortId))
                .filter((cohortId): cohortId is string => Boolean(cohortId))
        )
    );

    if (uniqueCohortIds.length === 0) {
        return new Map();
    }

    const { data, error } = await runWithTablePermissionFallback(
        supabase,
        "cohorts",
        async (client) =>
            await client
                .from("cohorts")
                .select("id, year")
                .in("id", uniqueCohortIds)
    );

    if (error) {
        console.error("Error fetching cohort years:", formatSupabaseError(error));
        return new Map();
    }

    return new Map(
        (data || []).flatMap((row) => {
            if (!row || typeof row !== "object") {
                return [];
            }

            const source = row as Record<string, unknown>;
            const id = getTrimmedString(source.id);
            if (!id) {
                return [];
            }

            return [[id, getCohortYear(source)]];
        })
    );
}

async function hydrateRowsWithCohortYears<T>(
    supabase: ServerSupabaseClient,
    rows: T[] | null | undefined
): Promise<T[]> {
    const cohortYearMap = await getCohortYearMap(
        supabase,
        (rows || []).flatMap((row) => {
            if (!row || typeof row !== "object") {
                return [];
            }

            const source = row as Record<string, unknown>;
            const hasCohortYear = source.cohort_year !== undefined && source.cohort_year !== null;
            const cohortId = getTrimmedString(source.cohort_id);

            return !hasCohortYear && cohortId ? [cohortId] : [];
        })
    );

    if (cohortYearMap.size === 0) {
        return rows || [];
    }

    return (rows || []).map((row) => {
        if (!row || typeof row !== "object") {
            return row;
        }

        const source = row as Record<string, unknown>;
        const cohortId = getTrimmedString(source.cohort_id);

        if (!cohortId || !cohortYearMap.has(cohortId)) {
            return row;
        }

        return {
            ...source,
            cohort_year: cohortYearMap.get(cohortId) ?? null,
        } as T;
    });
}

async function getAdminCohortsData(
    supabase: ServerSupabaseClient
) {
    const cohortsWithProgramsRes = await runWithTablePermissionFallback(
